// Pega os dados do item que ENTROU neste nó
const item = $input.item;

// 1. Tenta pegar o campo custom_fields
const camposRaw = item.json.custom_fields;

// Validação inicial
if (!camposRaw) {
  return [{ json: { conteudoNota: "⚠️ Sem informações encontradas." }}];
}

// 2. LÓGICA BLINDADA: Pega o ÚLTIMO elemento válido do array
let data = null;

try {
  if (Array.isArray(camposRaw)) {
    // Array vazio
    if (camposRaw.length === 0) {
      return [{ json: { conteudoNota: "⚠️ Array vazio de custom_fields." }}];
    }

    // Pega o último elemento não-vazio do array
    // Procura de trás pra frente até encontrar um objeto válido
    for (let i = camposRaw.length - 1; i >= 0; i--) {
      const item = camposRaw[i];
      if (item && typeof item === 'object' && Object.keys(item).length > 0) {
        data = item;
        break;
      }
    }

    // Se não encontrou nenhum objeto válido
    if (!data) {
      return [{ json: { conteudoNota: "⚠️ Nenhum objeto válido encontrado no array." }}];
    }
  } 
  // Formato antigo: string com escape duplo
  else if (typeof camposRaw === 'string') {
    try {
      const firstParse = JSON.parse(camposRaw);
      data = typeof firstParse === 'string' ? JSON.parse(firstParse) : firstParse;
    } catch (parseError) {
      return [{ json: { conteudoNota: `⚠️ Erro ao fazer parse da string: ${parseError.message}` }}];
    }
  }
  // Já é objeto direto
  else if (typeof camposRaw === 'object') {
    data = camposRaw;
  }
  else {
    return [{ json: { conteudoNota: `⚠️ Formato não reconhecido: ${typeof camposRaw}` }}];
  }
} catch (e) {
  return [{ json: { conteudoNota: `⚠️ Erro crítico ao processar: ${e.message}` }}];
}

// Validação final: data deve ser objeto válido
if (!data || typeof data !== 'object' || Array.isArray(data)) {
  return [{ json: { conteudoNota: "⚠️ Dados inválidos após processamento." }}];
}

// 3. Extrai os dados com fallback seguro
const dadosPessoais = (data.dados_pessoais && typeof data.dados_pessoais === 'object') 
  ? data.dados_pessoais : {};

const dadosBiometricos = (data.dados_biometricos && typeof data.dados_biometricos === 'object') 
  ? data.dados_biometricos : {};

const perfilComportamental = (data.perfil_comportamental && typeof data.perfil_comportamental === 'object') 
  ? data.perfil_comportamental : {};

const experienciaMedicacao = (data.experiencia_medicacao && typeof data.experiencia_medicacao === 'object') 
  ? data.experiencia_medicacao : {};

const preferenciasVenda = (data.preferencias_venda && typeof data.preferencias_venda === 'object') 
  ? data.preferencias_venda : {};

// 4. Monta objeto plano com acesso seguro (usando optional chaining mental)
const dadosFormatados = {
  nome: dadosPessoais.nome || null,
  telefone: dadosPessoais.telefone || null,
  cidade: dadosPessoais.cidade || null,
  peso_atual: dadosBiometricos.peso_atual_kg || null,
  altura: dadosBiometricos.altura_cm || null,
  peso_desejado: dadosBiometricos.peso_desejado_kg || null,
  imc: dadosBiometricos.imc || null,
  imc_categoria: dadosBiometricos.imc_categoria || null,
  momento_vida: perfilComportamental.momento_vida || null,
  maior_obstaculo: perfilComportamental.maior_obstaculo || null,
  motivacao: perfilComportamental.motivacao || null,
  uso_suplementos: perfilComportamental.uso_suplementos || null,
  historico_medicacao: experienciaMedicacao.historico || null,
  orcamento_mensal: preferenciasVenda.orcamento_mensal || null,
  protocolo_interesse: preferenciasVenda.protocolo_interesse || null
};

// 5. Mapeamento de Emojis
const emojiMap = {
  'nome': '👤',
  'telefone': '📱',
  'cidade': '📍',
  'peso_atual': '⚖️',
  'altura': '📏',
  'peso_desejado': '🎯',
  'imc': '📊',
  'imc_categoria': '📈',
  'momento_vida': '🔄',
  'maior_obstaculo': '🚧',
  'motivacao': '💪',
  'uso_suplementos': '💊',
  'historico_medicacao': '🩺',
  'orcamento_mensal': '💰',
  'protocolo_interesse': '⭐'
};

// Formata snake_case para Título
const formatLabel = (key) => {
  return key
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase());
};

// Formata valores com validação extra
const formatValue = (key, value) => {
  // Valores vazios/nulos
  if (value === null || value === undefined || value === '') return '-';

  // Conversão segura para string para evitar erros
  const strValue = String(value).trim();
  if (strValue === '') return '-';

  // Formatação específica
  if (key.includes('peso') && !isNaN(value)) return `${value} kg`;
  if (key === 'altura' && !isNaN(value)) return `${value} cm`;

  return strValue;
};

// Processador
const processData = (obj) => {
  let result = '';

  for (const [key, value] of Object.entries(obj)) {
    const emoji = emojiMap[key] || '🔹';
    const label = formatLabel(key);
    const valor = formatValue(key, value);

    result += `${emoji} **${label}:** ${valor}\n`;
  }

  return result;
};

// Montagem da Nota
let texto = `🧩 **RESUMO DO QUIZ**\n`;
texto += `━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
texto += processData(dadosFormatados);
texto += `\n━━━━━━━━━━━━━━━━━━━━━━━━`;

// Data e Hora Brasil com fallback
try {
  const agora = new Date();
  const dataHoraBrasil = new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    dateStyle: 'short',
    timeStyle: 'short'
  }).format(agora);
  texto += `\n📅 **Atualizado em:** ${dataHoraBrasil}`;
} catch (dateError) {
  // Fallback se houver erro na formatação de data
  texto += `\n📅 **Atualizado em:** ${new Date().toISOString()}`;
}

return [{ json: { conteudoNota: texto }}];

// 1. Tags que você deseja adicionar (se não existirem)
const tagsParaAdicionar = "5-realizar-onboarding-ia";

// 2. Tags que você deseja remover (se existirem)
// Deixe vazio ("") ou liste as tags separadas por vírgula.
const tagsParaRemover = "";

// 3. Pega o array de tags do nó anterior "Get Tags" (usando sintaxe V1)
// Se não houver tags existentes, será um array vazio ([]).
const tagsExistentes = $('Get Tags').first().json.payload || [];


// --- Processamento ---

// 4. Cria um Set de todas as tags que DEVERÃO PERMANECER ou SER ADICIONADAS
const setDeTagsFinais = new Set();

// 5. Converte a string de tags a serem removidas para um Set para pesquisa rápida
const setDeTagsParaRemover = new Set(
    tagsParaRemover.split(',').map(tag => tag.trim()).filter(tag => tag.length > 0)
);

// 6. Adiciona ao SetFinais as tags EXISTENTES que NÃO DEVEM ser removidas
tagsExistentes.forEach(tag => {
    // Adiciona a tag existente APENAS se ela NÃO estiver na lista de remoção
    if (!setDeTagsParaRemover.has(tag)) {
        setDeTagsFinais.add(tag);
    }
});

// 7. Adiciona as tags NOVAS/DESEJADAS ao SetFinais (o Set ignora duplicatas automaticamente)
const tagsNovas = tagsParaAdicionar.split(',').map(tag => tag.trim());
tagsNovas.forEach(tag => {
    // Adiciona a tag APENAS se ela NÃO estiver na lista de remoção (para garantir)
    if (!setDeTagsParaRemover.has(tag)) {
        setDeTagsFinais.add(tag);
    }
});


// --- Saída ---

// 8. Converte o Set de volta para um Array
const tagsArray = Array.from(setDeTagsFinais);

// 9. Mapeia o array para adicionar as aspas em cada tag e junta em uma string.
const tagsAtualizadasString = tagsArray
    .map(tag => `"${tag}"`) // Adiciona aspas (ex: "tag_a")
    .join(','); // Junta as tags com vírgula (ex: "tag_a","tag_b")

// 10. Retorna o resultado no formato de string
