lead_existente AS (
  SELECT 
    *,
    (chatwoot_contact_id IS NOT NULL) as cadastrado,
    false as is_insert  -- ← ADICIONAR ESTA LINHA
  FROM leads
  WHERE 
    -- 1. BUSCA por identificadores WhatsApp
    (whatsapp_jid = (SELECT whatsapp_jid FROM whatsapp_data) AND (SELECT whatsapp_jid FROM whatsapp_data) IS NOT NULL)
    OR (whatsapp_lid = (SELECT whatsapp_lid FROM whatsapp_data) AND (SELECT whatsapp_lid FROM whatsapp_data) IS NOT NULL)
    OR (whatsapp_identificador_ativo = (SELECT whatsapp_identificador_ativo FROM whatsapp_data) AND (SELECT whatsapp_identificador_ativo FROM whatsapp_data) IS NOT NULL)

    -- 2. BUSCA FLEXÍVEL por telefone (tenta múltiplas variações)
    OR (
      phone_number IS NOT NULL 
      AND (
        regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_clean FROM telefone_limpo)
        OR regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_sem_9 FROM telefone_limpo WHERE phone_sem_9 IS NOT NULL)
        OR regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_com_9 FROM telefone_limpo WHERE phone_com_9 IS NOT NULL)
      )
    )
  LIMIT 1
),
