    utm_campaign = COALESCE(leads.utm_campaign, {{ $('Parse e Validar').item.json.utm_campaign ? `'${$('Parse e Validar').item.json.utm_campaign}'` : 'NULL' }}),
    landing_page = COALESCE(leads.landing_page, {{ $('Parse e Validar').item.json.landing_page ? `'${$('Parse e Validar').item.json.landing_page}'` : 'NULL' }}),
    origem = COALESCE(leads.origem, {{ $('Parse e Validar').item.json.source ? `'${$('Parse e Validar').item.json.source}'` : 'NULL' }}),
    agente_responsavel_id = COALESCE(leads.agente_responsavel_id, {{ $('Parse e Validar').item.json.routing_metadata?.agente_padrao ? `'${$('Parse e Validar').item.json.routing_metadata.agente_padrao}'` : 'NULL' }}),

    -- Estado (mantém lógica original)
    estado_atual = COALESCE(leads.estado_atual, (SELECT id FROM estados_lead WHERE nome = '{{ $('Parse e Validar').item.json.routing_metadata?.estado_inicial_nome || $('Parse e Validar').item.json.routing_metadata?.estado_inicial }}' LIMIT 1)),
    estado_alterado_em = CASE 
