parameters.jsCode:
// --- Parse evento do RabbitMQ ---
const rawMessage = $input.first().json;
const eventData = (typeof rawMessage === 'string')
  ? JSON.parse(rawMessage)
  : rawMessage;

const routingKey = eventData.fields?.routingKey || null;
const exchange = eventData.fields?.exchange || null;
const deliveryTag = eventData.fields?.deliveryTag || null;

let leadData;
try {
  if (typeof eventData.content === 'string') {
    leadData = JSON.parse(eventData.content);
  } else {
    leadData = eventData.content;
  }
} catch (err) {
  throw new Error(`Erro ao fazer parse do campo content: ${err.message}`);
}

// --- Validações ---
if (!routingKey || routingKey !== 'aquisicao.lead.criado') {
  throw new Error(`Evento inesperado: ${routingKey}`);
}
if (!leadData.fullName) {
  throw new Error('Campo fullName ausente no payload do lead');
}

// --- Parse custom_fields para OBJETO ---
let customFieldsObj = {};

if (leadData.customFields) {
  customFieldsObj = typeof leadData.customFields === 'string'
    ? JSON.parse(leadData.customFields)
    : leadData.customFields;
} else if (leadData.tags?.interesse) {
  customFieldsObj = typeof leadData.tags.interesse === 'string'
    ? JSON.parse(leadData.tags.interesse)
    : leadData.tags.interesse;
}

// --- Parse routing_metadata para OBJETO (Novo) ---
let routingMetadataObj = {}; // Inicia vazio caso não exista

if (leadData.routing_metadata) {
  routingMetadataObj = typeof leadData.routing_metadata === 'string'
    ? JSON.parse(leadData.routing_metadata)
    : leadData.routing_metadata;
}

// --- Retorno ---
return [{
  json: {
    event_name: routingKey,
    exchange,
    delivery_tag: deliveryTag,
    event_timestamp: leadData.webhookReceivedAt || new Date().toISOString(),
    lead_id: leadData.leadId || null,
    full_name: leadData.fullName,
    email: leadData.email || null,
    phone_number: leadData.phoneNumber || null,
    source: leadData.source || 'Desconhecido',
    custom_fields: customFieldsObj,      // Mantido como estava
    routing_metadata: routingMetadataObj // ← Novo campo adicionado
  }
}];

// Estratégia: Usar try/catch para cada nó e verificar se foi executado

// Função helper para buscar dados de forma segura
const getSafeData = (nodeName, path) => {
  try {
    const node = $(nodeName);
    if (!node || !node.first()) return null;

    // Navega pelo path (ex: "json.id")
    const parts = path.split('.');
    let value = node.first();

    for (const part of parts) {
      if (value && value[part] !== undefined) {
        value = value[part];
      } else {
        return null;
      }
    }

    return value;
  } catch (e) {
    return null;
  }
};

// Busca o leadId de forma segura
const leadIdInsert = getSafeData('Insert Novo Lead', 'json.id');
const leadIdUpdate = getSafeData('Update Lead Existente', 'json.id');
const leadId = leadIdInsert ?? leadIdUpdate;

// Determina a ação
const action = leadIdInsert ? 'created' : 'updated';

// Busca o chatwootContactId da query "Salvar Chatwoot ID"
const chatwootContactId = getSafeData('Salvar Chatwoot ID', 'json.chatwoot_contact_id');

// Timestamp ISO (padrão internacional)
const timestampISO = new Date().toISOString();

// Timestamp Brasil (legível)
const timestampBR = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
}).format(new Date());

return [{
  json: {
    success: true,
    leadId: leadId,
    action: action,
    chatwootContactId: chatwootContactId,
    timestamp: timestampISO,
    timestampBR: timestampBR,
    // Informações para debug/monitoramento
    metadata: {
      hasLeadId: !!leadId,
      hasChatwootId: !!chatwootContactId,
      executionSource: action === 'created' ? 'Insert Novo Lead' : 'Update Lead Existente',
      chatwootSource: 'Salvar Chatwoot ID'
    }
  }
}];

// Pega os dados do item atual
const item = $input.item;

// 1. Tenta pegar o array de custom_fields
const camposRaw = item.json.custom_fields;

// Validação inicial
if (!camposRaw || (Array.isArray(camposRaw) && camposRaw.length === 0)) {
  return [{ conteudoNota: "⚠️ Sem informações de interesse encontradas." }];
}

// 2. Pega o último item se for array
let interesseRaw = Array.isArray(camposRaw)
  ? camposRaw[camposRaw.length - 1]
  : camposRaw;

// 3. Parse inteligente e resiliente (1 ou 2 camadas de JSON)
let data;

try {
  if (typeof interesseRaw === "string") {
    let parsed = JSON.parse(interesseRaw);
    if (typeof parsed === "string") {
      parsed = JSON.parse(parsed);
    }
    data = parsed;
  } else {
    data = interesseRaw;
  }
} catch (e) {
  return [{ conteudoNota: "❌ Erro ao interpretar JSON em custom_fields." }];
}

// --- CONFIGURAÇÕES DE EXIBIÇÃO ---

// Blocos que NÃO devem aparecer
const blocosRemovidos = ['jornada_quiz', 'estrategia_ia', 'scoring'];

// Emoji por bloco
const emojiMap = {
  'lead_id': '🆔',
  'quiz_type': '📝',
  'dados_pessoais': '👤',
  'dados_biometricos': '⚖️',
  'experiencia_medicacao': '💊',
  'metadata': '🔖',
  'default': '📋'
};

const formatLabel = (key) =>
  key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

const formatValue = (value) => {
  if (value === null || value === undefined) return '-';
  if (typeof value === 'boolean') return value ? '✅ Sim' : '❌ Não';
  if (typeof value === 'object' && !Array.isArray(value)) return '[Objeto]';
  if (Array.isArray(value)) return value.join(', ');
  return value;
};

// --- PROCESSAMENTO PRINCIPAL ---
const processData = (obj) => {
  let result = '';

  // Separa metadata para jogar no final
  const entries = Object.entries(obj)
    .filter(([key]) => !blocosRemovidos.includes(key) && key !== 'metadata');

  const metadataEntry = obj.metadata ? [['metadata', obj.metadata]] : [];

  const orderedEntries = [...entries, ...metadataEntry];

  for (const [key, value] of orderedEntries) {
    if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      const emoji = emojiMap[key] || emojiMap['default'];
      const title = formatLabel(key);

      result += `\n${emoji} **${title}**\n`;

      for (const [subKey, subValue] of Object.entries(value)) {
        const subLabel = formatLabel(subKey);
        const subValor = formatValue(subValue);
        result += `  • ${subLabel}: ${subValor}\n`;
      }
    }
  }

  return result.trim();
};

// --- SAÍDA FINAL ---
return [
  {
    conteudoNota: processData(data)
  }
];

// Nó: "Buscar Contato Chatwoot Inteligente v2"

// ========================================
// 1. CONFIGURAÇÃO
// ========================================
const CHATWOOT_CONFIG = {
  url: 'https://chat.aplicgo.com',
  accountId: '1',
  apiKey: 'fmURrfLvWrJbtkAu6RUtQLYn',
  retryDelay: 600 // ms entre tentativas
};

// ========================================
// 2. RECUPERAÇÃO DE DADOS DO LEAD
// ========================================
const getSafeData = (nodeName) => {
  try {
    const node = $(nodeName);
    return node?.first()?.json || null;
  } catch {
    return null;
  }
};

const leadData = 
  getSafeData('Insert Novo Lead') || 
  getSafeData('Update Lead Existente') || 
  $input.first()?.json;

if (!leadData) {
  throw new Error('❌ Não foi possível recuperar dados do lead');
}

console.log('✅ Dados do lead recuperados:', leadData.id);

// ========================================
// 3. FUNÇÃO DE BUSCA (FORMATO N8N CORRETO)
// ========================================
async function buscarContato(query, tipo) {
  if (!query) return null;

  try {
    console.log('🔍 Buscando por ' + tipo + ': "' + query + '"');

    const options = {
      method: 'GET',
      url: `${CHATWOOT_CONFIG.url}/api/v1/accounts/${CHATWOOT_CONFIG.accountId}/contacts/search`,
      qs: { q: query },
      headers: {
        'api_access_token': CHATWOOT_CONFIG.apiKey,
        'Content-Type': 'application/json'
      },
      json: true
    };

    const response = await this.helpers.httpRequest(options);

    // console.log('📡 Resposta:', JSON.stringify(response));

    const contato = (response.payload && response.payload.length > 0) ? response.payload[0] : null;

    if (contato) {
      console.log('✅ Encontrado por ' + tipo + '!');
    }

    return contato;

  } catch (error) {
    // Trata erro 422 (não encontrado) como resultado vazio
    if (error.statusCode === 422) {
      console.log('ℹ️ Não encontrado por ' + tipo + ' (422)');
      return null;
    }
    console.log('❌ Erro na busca por ' + tipo + ':', error.message);
    return null;
  }
}

// ========================================
// 4. PREPARAÇÃO DAS VARIAÇÕES DE TELEFONE
// ========================================
const telefoneRaw = leadData.phone_number || '';
// Remove tudo que não for número
const telefone = telefoneRaw.replace(/\D/g, '');
const email = leadData.email || '';

// Gera todas as variações de telefone
const variacoesTelefone = [];

if (telefone) {
  // 1. Telefone completo (ex: 5541988887777)
  variacoesTelefone.push({ query: telefone, tipo: 'telefone_completo' });

  // 2. Sem código do país - 55 (ex: 41999887766)
  if (telefone.startsWith('55') && telefone.length > 11) {
    variacoesTelefone.push({ 
      query: telefone.slice(2), 
      tipo: 'telefone_sem_codigo_pais' 
    });
  }

  // >>> NOVA LÓGICA SOLICITADA <<<
  // 2.5. Formato Antigo: Remove 55 E remove o 9 verificador
  // Lógica: Se tem 13 dígitos, começa com 55 e o quinto dígito é 9 (índice 4)
  // Ex Entrada: 55 41 9 88887777 -> Saída: 4188887777
// 2.5. Formato Antigo: Remove o 9 verificador (celulares)
  // Funciona para: 5541988887777 (13 dig) OU 41988887777 (11 dig)
  const temNove = telefone.length >= 11 && telefone[telefone.length - 9] === '9';

  if (temNove) {
    // Remove o 9 que está na 3ª posição dos últimos 9 dígitos
    const parte1 = telefone.slice(0, -9); // Tudo antes dos 9 dígitos finais
    const ddd = telefone.slice(-11, -9); // DDD (2 dígitos antes do 9)
    const numeroSem9 = telefone.slice(-8); // 8 dígitos finais

    variacoesTelefone.push({
      query: parte1 + ddd + numeroSem9,
      tipo: 'telefone_legacy_sem_9'
    });
  }

  // 3. Últimos 8 dígitos (ex: 88887766)
  // Útil para buscar quando o DDD está incerto ou erro de formatação
  if (telefone.length >= 8) {
    variacoesTelefone.push({ 
      query: telefone.slice(-8), 
      tipo: 'telefone_reduzido' 
    });
  }

  // 4. Formato original (caso tenha caracteres especiais salvos no chatwoot)
  if (telefoneRaw !== telefone && telefoneRaw.length > 0) {
    variacoesTelefone.push({ 
      query: telefoneRaw, 
      tipo: 'telefone_original' 
    });
  }
}

console.log('📞 ' + variacoesTelefone.length + ' variações de telefone geradas para busca');
console.log('📧 Email:', email || 'não informado');

// ========================================
// 5. BUSCA SEQUENCIAL COM DELAY
// ========================================
let contato = null;
let encontradoPor = null;

// Busca por todas as variações de telefone
for (let i = 0; i < variacoesTelefone.length; i++) {
  const variacao = variacoesTelefone[i];

  contato = await buscarContato.call(this, variacao.query, variacao.tipo);

  if (contato) {
    encontradoPor = variacao.tipo;
    break;
  }

  // Delay entre tentativas (exceto na última)
  if (i < variacoesTelefone.length - 1) {
    await new Promise(resolve => setTimeout(resolve, CHATWOOT_CONFIG.retryDelay));
  }
}

// Busca por email como última tentativa
if (!contato && email) {
  await new Promise(resolve => setTimeout(resolve, CHATWOOT_CONFIG.retryDelay));
  contato = await buscarContato.call(this, email, 'email');
  if (contato) {
    encontradoPor = 'email';
  }
}

// ========================================
// 6. RETORNO (FORMATO N8N CORRETO)
// ========================================
if (!contato) {
  console.log('❌ Contato não encontrado após todas as tentativas');

  // Retorna estrutura indicando que não foi encontrado
  return [{
    json: {
      encontrado: false,
      tentativas: variacoesTelefone.length + (email ? 1 : 0),
      lead_id: leadData.id,
      lead_full_name: leadData.full_name,
      lead_email: leadData.email,
      lead_phone: leadData.phone_number
    }
  }];
}

console.log('🎉 Contato encontrado!');

return [{
  json: {
    // Dados do contato encontrado
    id: contato.id,
    name: contato.name,
    email: contato.email,
    phone_number: contato.phone_number,
    identifier: contato.identifier,

    //Payload Completo - Pode ser retirado se pesar
    payload_completo: contato,

    // Metadados da busca
    encontrado: true,
    encontrado_por: encontradoPor,

    // Dados originais do lead
    lead_id: leadData.id,
    lead_full_name: leadData.full_name,
    lead_email: leadData.email,
    lead_phone: leadData.phone_number,

    // Flags úteis para próximos nós
    tem_identifier: !!contato.identifier,
    identifier_valido: contato.identifier?.includes('@s.whatsapp.net') || false,
    precisa_update_email: !contato.email && !!leadData.email
  }
}];

