              const inWhatsapp = users && users[0] && users[0].IsInWhatsapp;
              const jid = users && users[0] ? users[0].JID : null;
              const parsed = $('Parse e Validar').item.json.phone_number;
              let raw = '';
              if (inWhatsapp && jid) { raw = jid.split('@')[0]; } 
              else if (parsed) { raw = parsed; } 
              else { return "''"; }
              const digits = raw.replace(/\D/g, '');
              const finalNumber = digits.length >= 11 ? digits : '5534' + digits;
              return "'" + finalNumber + "'";
            })()
          }},
          '[^0-9]', '', 'g'
        ), 1, 4) || '9' ||
        substring(regexp_replace(
          {{
            (() => {
              const data = $('DinastiAPI User1').item.json.data;
              const users = data && Array.isArray(data.Users) ? data.Users : null;
              const inWhatsapp = users && users[0] && users[0].IsInWhatsapp;
              const jid = users && users[0] ? users[0].JID : null;
              const parsed = $('Parse e Validar').item.json.phone_number;
              let raw = '';
