whatsapp_data AS (
  SELECT
    {{
      (() => {
        const data = $('DinastiAPI User1').item.json.data;
        const users = data && Array.isArray(data.Users) ? data.Users : null;
        const jid = users && users[0] ? users[0].JID : null;
        return jid ? "'" + jid + "'" : 'NULL';
      })()
    }} as whatsapp_jid,
    {{
      (() => {
        const data = $('DinastiAPI User1').item.json.data;
        const users = data && Array.isArray(data.Users) ? data.Users : null;
        const lid = users && users[0] ? users[0].LID : null;
        return lid ? "'" + lid + "'" : 'NULL';
      })()
    }} as whatsapp_lid,
    {{
      (() => {
        const data = $('DinastiAPI User1').item.json.data;
        const users = data && Array.isArray(data.Users) ? data.Users : null;
        const jid = users && users[0] ? users[0].JID : null;
        return jid ? "'" + jid + "'" : 'NULL';
      })()
    }} as whatsapp_identificador_ativo
),
lead_existente AS (
  SELECT 
    *,
    (chatwoot_contact_id IS NOT NULL) as cadastrado,
    false as is_insert  -- ← ADICIONAR ESTA LINHA
  FROM leads
  WHERE 
    -- 1. BUSCA por identificadores WhatsApp
    (whatsapp_jid = (SELECT whatsapp_jid FROM whatsapp_data) AND (SELECT whatsapp_jid FROM whatsapp_data) IS NOT NULL)
    OR (whatsapp_lid = (SELECT whatsapp_lid FROM whatsapp_data) AND (SELECT whatsapp_lid FROM whatsapp_data) IS NOT NULL)
    OR (whatsapp_identificador_ativo = (SELECT whatsapp_identificador_ativo FROM whatsapp_data) AND (SELECT whatsapp_identificador_ativo FROM whatsapp_data) IS NOT NULL)

    -- 2. BUSCA FLEXÍVEL por telefone (tenta múltiplas variações)
    OR (
      phone_number IS NOT NULL 
      AND (
        regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_clean FROM telefone_limpo)
        OR regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_sem_9 FROM telefone_limpo WHERE phone_sem_9 IS NOT NULL)
        OR regexp_replace(phone_number, '[^0-9]', '', 'g') = (SELECT phone_com_9 FROM telefone_limpo WHERE phone_com_9 IS NOT NULL)
      )
    )
  LIMIT 1
),
lead_atualizado AS (
  UPDATE leads
  SET
    -- Atualiza identificadores WhatsApp
    whatsapp_jid = COALESCE((SELECT whatsapp_jid FROM whatsapp_data), whatsapp_jid),
    whatsapp_lid = COALESCE((SELECT whatsapp_lid FROM whatsapp_data), whatsapp_lid),
    whatsapp_identificador_ativo = COALESCE((SELECT whatsapp_identificador_ativo FROM whatsapp_data), whatsapp_identificador_ativo),

    -- Atualiza phone_number somente se estava NULL
    phone_number = CASE
      WHEN phone_number IS NULL AND (SELECT phone_clean FROM telefone_limpo) != ''
      THEN '+' || (SELECT phone_clean FROM telefone_limpo)
      ELSE phone_number
    END,

    -- Merge de tags (mantém lógica original)
    tags = leads.tags || {{ $('Parse e Validar').item.json.tags ? `'${JSON.stringify($('Parse e Validar').item.json.tags).replace(/'/g, "''")}'::jsonb` : "'{}'::jsonb" }},

    -- Merge de custom_fields (mantém lógica original)
    custom_fields = COALESCE(leads.custom_fields, '[]'::jsonb) || {{ $('Parse e Validar').item.json.custom_fields ? `'[${JSON.stringify($('Parse e Validar').item.json.custom_fields).replace(/'/g, "''")}]'::jsonb` : "'[]'::jsonb" }},

    -- Source (mantém lógica original de append)
    source = CASE
      WHEN leads.source IS NULL OR leads.source = 'Desconhecido' THEN {{ `'${$('Parse e Validar').item.json.source}'` }}
      WHEN {{ `'${$('Parse e Validar').item.json.source}'` }} = ANY(string_to_array(REPLACE(leads.source, ', ', ','), ',')) THEN leads.source
      ELSE leads.source || ', ' || {{ `'${$('Parse e Validar').item.json.source}'` }}
    END,

    -- Campos que atualizam se estavam vazios
    full_name = COALESCE(leads.full_name, {{ `'${$('Parse e Validar').item.json.full_name}'` }}),
    email = COALESCE(leads.email, {{ $('Parse e Validar').item.json.email ? `'${$('Parse e Validar').item.json.email}'` : 'NULL' }}),
    utm_source = COALESCE(leads.utm_source, {{ $('Parse e Validar').item.json.utm_source ? `'${$('Parse e Validar').item.json.utm_source}'` : 'NULL' }}),
    utm_medium = COALESCE(leads.utm_medium, {{ $('Parse e Validar').item.json.utm_medium ? `'${$('Parse e Validar').item.json.utm_medium}'` : 'NULL' }}),
    utm_campaign = COALESCE(leads.utm_campaign, {{ $('Parse e Validar').item.json.utm_campaign ? `'${$('Parse e Validar').item.json.utm_campaign}'` : 'NULL' }}),
    landing_page = COALESCE(leads.landing_page, {{ $('Parse e Validar').item.json.landing_page ? `'${$('Parse e Validar').item.json.landing_page}'` : 'NULL' }}),
    origem = COALESCE(leads.origem, {{ $('Parse e Validar').item.json.source ? `'${$('Parse e Validar').item.json.source}'` : 'NULL' }}),
    agente_responsavel_id = COALESCE(leads.agente_responsavel_id, {{ $('Parse e Validar').item.json.routing_metadata?.agente_padrao ? `'${$('Parse e Validar').item.json.routing_metadata.agente_padrao}'` : 'NULL' }}),

    -- Estado (mantém lógica original)
    estado_atual = COALESCE(leads.estado_atual, (SELECT id FROM estados_lead WHERE nome = '{{ $('Parse e Validar').item.json.routing_metadata?.estado_inicial_nome || $('Parse e Validar').item.json.routing_metadata?.estado_inicial }}' LIMIT 1)),
    estado_alterado_em = CASE 
      WHEN leads.estado_atual IS DISTINCT FROM COALESCE(leads.estado_atual, (SELECT id FROM estados_lead WHERE nome = '{{ $('Parse e Validar').item.json.routing_metadata?.estado_inicial_nome || $('Parse e Validar').item.json.routing_metadata?.estado_inicial }}' LIMIT 1)) THEN NOW()
      ELSE leads.estado_alterado_em 
    END,

    updated_at = NOW()
  WHERE id = (SELECT id FROM lead_existente)
  RETURNING 
    *,
    (chatwoot_contact_id IS NOT NULL) as cadastrado,
    false as is_insert
),
lead_criado AS (
  INSERT INTO leads (
    full_name, email, phone_number, source, utm_source, utm_medium, utm_campaign, landing_page, tags, custom_fields,
    origem, estado_atual, agente_responsavel_id, estado_alterado_em,
    whatsapp_jid, whatsapp_lid, whatsapp_identificador_ativo,
    created_at, updated_at
  )
  SELECT 
    {{ `'${$('Parse e Validar').item.json.full_name}'` }},
    {{ $('Parse e Validar').item.json.email ? `'${$('Parse e Validar').item.json.email}'` : 'NULL' }},
    CASE 
      WHEN (SELECT phone_clean FROM telefone_limpo) != '' THEN '+' || (SELECT phone_clean FROM telefone_limpo)
      ELSE NULL
    END,
    {{ `'${$('Parse e Validar').item.json.source}'` }},
    {{ $('Parse e Validar').item.json.utm_source ? `'${$('Parse e Validar').item.json.utm_source}'` : 'NULL' }},
    {{ $('Parse e Validar').item.json.utm_medium ? `'${$('Parse e Validar').item.json.utm_medium}'` : 'NULL' }},
    {{ $('Parse e Validar').item.json.utm_campaign ? `'${$('Parse e Validar').item.json.utm_campaign}'` : 'NULL' }},
    {{ $('Parse e Validar').item.json.landing_page ? `'${$('Parse e Validar').item.json.landing_page}'` : 'NULL' }},
    {{ $('Parse e Validar').item.json.tags ? `'${JSON.stringify($('Parse e Validar').item.json.tags).replace(/'/g, "''")}'::jsonb` : "'{}'::jsonb" }},
    {{ $('Parse e Validar').item.json.custom_fields ? `'[${JSON.stringify($('Parse e Validar').item.json.custom_fields).replace(/'/g, "''")}]'::jsonb` : "'[]'::jsonb" }},
    {{ $('Parse e Validar').item.json.source ? `'${$('Parse e Validar').item.json.source}'` : 'NULL' }},
    (SELECT id FROM estados_lead WHERE nome = '{{ $('Parse e Validar').item.json.routing_metadata?.estado_inicial_nome || $('Parse e Validar').item.json.routing_metadata?.estado_inicial }}' LIMIT 1),
    {{ $('Parse e Validar').item.json.routing_metadata?.agente_padrao ? `'${$('Parse e Validar').item.json.routing_metadata.agente_padrao}'` : 'NULL' }},
    NOW(),
    (SELECT whatsapp_jid FROM whatsapp_data),
    (SELECT whatsapp_lid FROM whatsapp_data),
    (SELECT whatsapp_identificador_ativo FROM whatsapp_data),
    NOW(), NOW()
  WHERE NOT EXISTS (SELECT 1 FROM lead_existente)
  RETURNING 
    *,
    false as cadastrado,
    true as is_insert
)
SELECT * FROM lead_atualizado
UNION ALL
